Mapa: tasa de detección por comuna


ver código
ok &lt;- all(vapply(c("sf","leaflet","chilemapas","dplyr"), requireNamespace,
                 logical(1), quietly = TRUE))
if (!ok) {
  cat("&gt; Para ver el mapa instala: install.packages(c('sf','leaflet','chilemapas','dplyr'))")
} else {
  suppressPackageStartupMessages({library(sf); library(leaflet); library(chilemapas); library(dplyr)})
  terr &lt;- chilemapas::codigos_territoriales |&gt;
    dplyr::select(codigo_comuna, nombre_comuna, nombre_region) |&gt; dplyr::distinct()
  mapa &lt;- chilemapas::mapa_comunas |&gt; sf::st_as_sf()
  m &lt;- mapa |&gt;
    dplyr::left_join(as.data.frame(bre), by = c("codigo_comuna" = "cod_comuna")) |&gt;
    dplyr::left_join(terr, by = "codigo_comuna") |&gt;
    sf::st_transform(4326)
  pal &lt;- leaflet::colorNumeric("YlGnBu", domain = c(0, max(m$tasa_deteccion, na.rm = TRUE)),
                               na.color = "#eeeeee")
  etiqueta &lt;- sprintf(
    "&lt;b&gt;%s&lt;/b&gt; (%s)&lt;br/&gt;Detección: &lt;b&gt;%s&lt;/b&gt; · Brecha: %s&lt;br/&gt;Bajo control: %s · Esperados: %s&lt;br/&gt;Zona: %s",
    m$nombre_comuna, m$nombre_region, pct(m$tasa_deteccion,1), pct(m$brecha,1),
    mil(m$bajo_control_65), mil(round(m$esperados)), ifelse(is.na(m$zona),"s/i",m$zona)) |&gt;
    lapply(htmltools::HTML)
  leaflet(m, options = leafletOptions(minZoom = 3)) |&gt;
    addProviderTiles(providers$CartoDB.PositronNoLabels) |&gt;
    addPolygons(fillColor = ~pal(tasa_deteccion), weight = 0.4, color = "#888",
                fillOpacity = 0.85, label = etiqueta,
                highlightOptions = highlightOptions(weight = 2, color = "#222", bringToFront = TRUE)) |&gt;
    addLegend(pal = pal, values = ~tasa_deteccion, title = "Tasa de&lt;br/&gt;detección",
              labFormat = labelFormat(suffix = "", transform = function(x) round(100*x)),
              position = "bottomright") |&gt;
    setView(lng = -72, lat = -38, zoom = 4)
}




Tasa de detección de demencia (bajo control SM 65+ / demencia esperada). Pase el cursor para ver el detalle comunal.
